class Solution:
    def numberOfSubarrays(self, nums) -> int:
        n = len(nums)
        count = 0
        for l in range(n):
            max_val = nums[l]
            for r in range(l, n):
                max_val = max(max_val, nums[r])
                if nums[l] == nums[r] == max_val:
                    count += 1
        return count

