class Solution:
    def numberOfSubarrays(self, nums) -> int:
        # stack stores (value, count) in decreasing order
        stack = []  # (val, count)
        result = 0
        for x in nums:
            count = 1  # the element itself (singleton)
            while stack and stack[-1][0] < x:
                stack.pop()
            if stack and stack[-1][0] == x:
                val, cnt = stack.pop()
                count += cnt
                result += cnt  # valid pairs with same value
            stack.append((x, count))
            result += 1  # singleton
        return result

