var numberOfSubarrays = function(nums) {
    const stack = []; // [val, count]
    let result = 0;
    for (const x of nums) {
        let count = 1;
        while (stack.length > 0 && stack[stack.length-1][0] < x) stack.pop();
        if (stack.length > 0 && stack[stack.length-1][0] === x) {
            const [val, cnt] = stack.pop();
            count += cnt;
            result += cnt;
        }
        stack.push([x, count]);
        result += 1;
    }
    return result;
};
